first_generated_sql:
SELECT COUNT(DISTINCT d.dealer_sk)
FROM dim_dealer d
WHERE d.is_current_record = TRUE
  AND d.termination_date IS NULL
  AND NOT EXISTS (
    SELECT 1 FROM fact_loan_contracts lc WHERE lc.dealer_sk = d.dealer_sk
  )
  AND NOT EXISTS (
    SELECT 1 FROM fact_leasing_contracts lc2 WHERE lc2.dealer_sk = d.dealer_sk
  );

